def knight_tour(n):
    board = [[0 for _ in range(n)] for _ in range(n)]

    knight_moves = [
        (2, 1), (1, 2), (-1, 2), (-2, 1),
        (-2, -1), (-1, -2), (1, -2), (2, -1)
    ]

    def is_valid(x, y):
        return 0 <= x < n and 0 <= y < n and board[x][y] == 0

    def solve(x, y, move_count):
        if move_count == n * n:
            return True

        for move_x, move_y in knight_moves:
            next_x, next_y = x + move_x, y + move_y
            if is_valid(next_x, next_y):
                board[next_x][next_y] = move_count + 1
                if solve(next_x, next_y, move_count + 1):
                    return True
                board[next_x][next_y] = 0
        return False

    board[0][0] = 1
    if solve(0, 0, 1):
        for row in board:
            print(" ".join(f"{cell:3d}" for cell in row))
        return True
    else:
        print(f"No solution exists for N={n}")
        return False
